transform_js:
const tree = [];
const catMap = {};
rawData.rows.forEach(r => {
  if (!catMap[r.category]) {
    catMap[r.category] = { name: r.category, children: [] };
    tree.push(catMap[r.category]);
  }
  catMap[r.category].children.push({ name: r.subcategory, value: r.value });
});
transformedData = tree;

echarts_js:
option = {
  title: {
    text: '商品カテゴリ別の売上構成',
    left: 'center'
  },
  tooltip: {
    trigger: 'item',
    formatter: '{b}: {c}'
  },
  series: [
    {
      type: 'treemap',
      roam: false,
      nodeClick: false,
      breadcrumb: {
        show: false
      },
      data: transformedData,
      label: {
        show: true,
        formatter: '{b}\n{c}'
      },
      upperLabel: {
        show: true,
        height: 30,
        color: '#fff',
        fontSize: 14
      },
      itemStyle: {
        borderColor: '#fff',
        borderWidth: 1,
        gapWidth: 1
      },
      levels: [
        {
          itemStyle: {
            borderColor: '#777',
            borderWidth: 2,
            gapWidth: 2
          },
          colorMappingBy: 'id'
        },
        {
          colorSaturation: [0.35, 0.5],
          itemStyle: {
            borderWidth: 1,
